  "verses": [
    {
      "n": 11,
      "column": "left",
      "text": "Deggoschas Ohygles taps\npahr teem frattitas/ wiꞥſch ar\nUggunt tohs eekſch dsittahm\nBedrehm noſittihs/ ka tee wairs\nne zettahs.\n"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Weens Plukschſis ne pa-\nſahwehs wirs Semmes/ weens\nnikns Warras- Darritajs taps\nwajahts/ teekams tas buhs ats-\ndſihts.\n"
    },
    {
      "n": 13,
      "column": "left",
      "text": "Es finnu/ ka tas KUNgs\nta Nabbaga Leetas/ un to Beh-\nvigo Teefu isteeſahs.\n"
    },
    {
      "n": 14,
      "column": "left",
      "text": "Teescham / tee Taifnee\ntawain Wahrdam pateiks/ tee\nSirđs-Skaidree tawā Preekſcha lihds\npastahwehs.\n"
    },
    {
      "n": 1,
      "column": "left",
      "text": "Ta CXLI. Dseesma.\nIre weena Luhgſchana Dahwida / ka Deews\nwinnu preeksch besdeewigas Mahzibas pa-\nfargaht: 1. Tehwijei pahrmahyht : 5.\nBet rohs wiltigus Mahzitajus isdeldeht\ngribbetu: 6.\n"
    },
    {
      "n": 2,
      "column": "left",
      "text": "Weena Dahwida Dseesma.\nUNEṠ/tewis prefauzu\nres/ steidscs pee mannis/\natgrees tahs Aufis pee\nmannu Balti/ kad es tewis pee-\nuzn.\n"
    },
    {
      "n": 3,
      "column": "left",
      "text": "Lat manna Luhgſchann ta-\ná Preekſchá tohp eezeenita / ka\nwebpja-Uppuris/ mannu Rob-\ni Pazelschana/ ka tas Watka-\nUppuris.\n"
    },
    {
      "n": 4,
      "column": "left",
      "text": "KUNGS/ apsargt mannu\nutti/ un pasargt mannas\nhpas.\n"
    },
    {
      "n": 5,
      "column": "left",
      "text": "Ne nolohki mannu Sirđi dsaima.\n"
    },
    {
      "n": 1,
      "column": "right",
      "text": "tu besdeewigu Darbu darrijs ar\nteem Launadarritajeem / un ka\nesno winzu Kahribahm ne ehnu.\n"
    },
    {
      "n": 5,
      "column": "right",
      "text": "Lai tas Taifnajs mannis\nfitt/ tas buhs Schehlastiba/ uu\nlai wiꞥſch mannis pahrmahza/\ntas buhs Etje us mannu Galwu/\nbet lai wiꞥſch man to Galwu ne\nlausch/ jo es arridsan weenumehr\nluhdsu prett winnu tauneem\nDarbeem.\n"
    },
    {
      "n": 6,
      "column": "right",
      "text": "Lai winnu Sohgi pee Ak-\nmineem tohp peedausitt/ tad dsir-\ndehs mannu Mahzibu mihligu\neſtam.\n"
    },
    {
      "n": 7,
      "column": "right",
      "text": "Muhfu Kauli irr iskaifiti\npascham Rappain / itt ka\nweens to Semmi usplehſch un\nisraufch.\n"
    },
    {
      "n": 8,
      "column": "right",
      "text": "Bet ns tevi KUNGS/\nKungs rauga mannas Azis/ us\ntewi es patariobs / ne atsuim\nmannu Dreheſeli.\n"
    },
    {
      "n": 9,
      "column": "right",
      "text": "Pafargt mann no ta Wal-\nga/ ko tee mann irr isplehtuſchi/\nun no to Launadarritajn Slas-\nda-Walgeem.\n"
    },
    {
      "n": 10,
      "column": "right",
      "text": "Tee Resdeewigee krittibs\ntawds Tihklos/ teekams es wiſ-\nfat buhschu fezzen gahjis.\n"
    },
    {
      "n": 1,
      "column": "right",
      "text": "Ta CXLII. Dseesma.\nIre weena krahtschana Luhgſchana Dahwida /\nka Drews winnu gribbetu peekemt: 1/4.\nUn us winna taifnu Leetu flattiht: 5. Jo\nwiꞥſch palaischahs us winnu: 6. Un grib\nlohti par to pateikt: 8.\n"
    },
    {
      "n": 2,
      "column": "right",
      "text": "Eena Dahwida Pa-\nmahzischana / kad\nwiꞥſch Alla bija / luh-\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
